  const nextBirthday = valid ? new Date(asOfDate.getFullYear(), birthDate.getMonth(), birthDate.getDate()) : null;
  if (nextBirthday && nextBirthday <= asOfDate) nextBirthday?.setFullYear(nextBirthday.getFullYear() + 1);
